#!/usr/bin/env python3
"""Merge user data from three sources by priority (A > B > C)."""
import csv
import json

import pandas as pd

# Field name -> unified name mapping (per source keys handled below)
FIELD_MAP = {
    "user_id": "user_id", "id": "user_id", "userId": "user_id",
    "email": "email", "email_address": "email",
    "full_name": "name", "name": "name", "userName": "name",
    "registration_date": "created_date", "created_at": "created_date", "joined": "created_date",
    "status": "status",
}

UNIFIED_FIELDS = ["name", "email", "created_date", "status"]
PRIORITY = ["source_a", "source_b", "source_c"]


def normalize(raw: dict) -> dict:
    """Map raw record keys to unified field names."""
    out = {}
    for k, v in raw.items():
        if k in FIELD_MAP:
            out[FIELD_MAP[k]] = v
    return out


def to_date(v):
    if v is None or (isinstance(v, float) and pd.isna(v)):
        return None
    return pd.to_datetime(v).strftime("%Y-%m-%d")


def load_source_a():
    with open("/data/source_a/users.json") as f:
        return [normalize(r) for r in json.load(f)]


def load_source_b():
    recs = []
    with open("/data/source_b/users.csv", newline="") as f:
        for row in csv.DictReader(f):
            recs.append(normalize(row))
    return recs


def load_source_c():
    df = pd.read_parquet("/data/source_c/users.parquet")
    return [normalize(r) for r in df.to_dict(orient="records")]


def clean(rec: dict) -> dict:
    """Coerce types/format for a normalized record."""
    out = dict(rec)
    out["user_id"] = int(out["user_id"])
    if "created_date" in out:
        out["created_date"] = to_date(out["created_date"])
    for k in ("name", "email", "status"):
        if k in out and out[k] is not None and not (isinstance(out[k], float) and pd.isna(out[k])):
            out[k] = str(out[k])
    return out


def main():
    sources = {
        "source_a": [clean(r) for r in load_source_a()],
        "source_b": [clean(r) for r in load_source_b()],
        "source_c": [clean(r) for r in load_source_c()],
    }

    # Index by user_id per source
    by_user = {}  # user_id -> {source: record}
    for src, recs in sources.items():
        for r in recs:
            by_user.setdefault(r["user_id"], {})[src] = r

    merged_rows = []
    conflicts = []

    for user_id in sorted(by_user):
        present = by_user[user_id]
        row = {"user_id": user_id}

        for field in UNIFIED_FIELDS:
            # Collect values per source that has a non-null value for this field
            values = {}
            for src in PRIORITY:
                if src in present:
                    v = present[src].get(field)
                    if v is not None and not (isinstance(v, float) and pd.isna(v)):
                        values[src] = v

            if not values:
                row[field] = None
                continue

            # Highest priority value wins
            selected = None
            for src in PRIORITY:
                if src in values:
                    selected = values[src]
                    break
            row[field] = selected

            # Conflict = multiple sources with differing values
            distinct = set(values.values())
            if len(distinct) > 1:
                conflicts.append({
                    "user_id": user_id,
                    "field": field,
                    "values": values,
                    "selected": selected,
                })

        merged_rows.append(row)

    # Write merged parquet
    df = pd.DataFrame(merged_rows, columns=["user_id", "name", "email", "created_date", "status"])
    df["user_id"] = df["user_id"].astype("int64")
    for c in ("name", "email", "created_date", "status"):
        df[c] = df[c].astype("object")
    df.to_parquet("/app/merged_users.parquet", index=False)

    report = {"total_conflicts": len(conflicts), "conflicts": conflicts}
    with open("/app/conflicts.json", "w") as f:
        json.dump(report, f, indent=2)

    print(df.to_string())
    print("\nConflicts:", len(conflicts))
    print(json.dumps(report, indent=2))


if __name__ == "__main__":
    main()

